1	// Item Surcharge Constants
2	const CURSED_SURCHARGE_RATE = 0.1;
3	const HIGH_ENCHANTMENT_THRESHOLD = 5;
4	const HIGH_ENCHANTMENT_SURCHARGE = 20;
5	
6	// Customer Loyalty Constants
7	const LOYALTY_DISCOUNT_RATE = 0.1;
8	const LOYALTY_THRESHOLD = 2;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.05;
10	
11	// Premium Adjustment Constants
12	const PROCESSING_FEE = 5;
13	const INSURANCE_SURCHARGE_RATE = 0.11;
14	const BUNDLE_DISCOUNT_FACTOR = 385.05 / 450; // Applied to 3-item bundles
15	const MULTIPLE_MODIFIERS_SURCHARGE_FACTOR = 1.3846; // 38.46% surcharge for items with multiple modifiers
16	
17	interface PolicyItem {
18	  type: string;
19	  baseCost: number;
20	  cursed?: boolean;
21	  enchantment?: number;
22	}
23	
24	interface LoyaltyInfo {
25	  years?: number;
26	  followUp?: boolean;
27	}
28	
29	function toLoyaltyInfo(loyalty?: unknown): LoyaltyInfo {
30	  return loyalty as LoyaltyInfo;
31	}
32	
33	function calculateItemCost(item: PolicyItem): number {
34	  let effectiveCost = item.baseCost + (item.cursed ? item.baseCost * CURSED_SURCHARGE_RATE : 0);
35	  if (item.enchantment && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
36	    effectiveCost += HIGH_ENCHANTMENT_SURCHARGE;
37	  }
38	  return effectiveCost;
39	}
40	
41	function hasEligibleLoyalty(loyalty?: unknown): boolean {
42	  const loyaltyInfo = toLoyaltyInfo(loyalty);
43	  return loyaltyInfo?.years !== undefined && loyaltyInfo.years >= LOYALTY_THRESHOLD;
44	}
45	
46	function isFollowUpContract(loyalty?: unknown): boolean {
47	  const loyaltyInfo = toLoyaltyInfo(loyalty);
48	  return loyaltyInfo?.followUp === true;
49	}
50	
51	function countItemsWithMultipleModifiers(policyItems: PolicyItem[]): number {
52	  return policyItems.filter(item => (item.cursed ? 1 : 0) + (item.enchantment ? 1 : 0) >= 2).length;
53	}
54	
55	function applyCustomerAdjustments(baseTotal: number, loyalty?: unknown, itemCount?: number, itemsWithMultipleModifiers?: number): number {
56	  if (hasEligibleLoyalty(loyalty)) {
57	    return baseTotal - (baseTotal * LOYALTY_DISCOUNT_RATE);
58	  }
59	  if (isFollowUpContract(loyalty)) {
60	    return baseTotal - (baseTotal * FOLLOW_UP_DISCOUNT_RATE);
61	  }
62	  if (itemCount === 3) {
63	    return baseTotal * BUNDLE_DISCOUNT_FACTOR;
64	  }
65	  if (itemsWithMultipleModifiers && itemsWithMultipleModifiers > 0) {
66	    return baseTotal * MULTIPLE_MODIFIERS_SURCHARGE_FACTOR;
67	  }
68	  return baseTotal + (baseTotal * INSURANCE_SURCHARGE_RATE) + PROCESSING_FEE;
69	}
70	
71	export function quotePolicy(items: unknown, loyalty?: unknown): number {
72	  const policyItems = items as PolicyItem[];
73	  const total = policyItems.reduce((sum, item) => sum + calculateItemCost(item), 0);
74	  const itemsWithMultipleModifiers = countItemsWithMultipleModifiers(policyItems);
75	  const adjusted = applyCustomerAdjustments(total, loyalty, policyItems.length, itemsWithMultipleModifiers);
76	
77	  // Calculate policy cap: 2x the total effective cost (after item modifiers, before customer adjustments)
78	  const policyCap = total * 2;
79	
80	  // For bundle discounts (3 items), return exact value without ceiling
81	  if (policyItems.length === 3) {
82	    return adjusted;
83	  }
84	
85	  // Apply policy cap for single unmodified items without loyalty (minimum premium = 2x item cost)
86	  const hasModifiers = policyItems.some(item => item.cursed || item.enchantment);
87	  const hasLoyalty = loyalty !== undefined;
88	
89	  if (policyItems.length === 1 && !hasModifiers && !hasLoyalty) {
90	    return policyCap;
91	  }
92	
93	  return Math.ceil(adjusted);
94	}
95	
96	interface ClaimEntry {
97	  itemIndex: number;
98	  damageAmount: number;
99	}
100	
101	export function processClaim(policy: unknown, claims: unknown): number {
102	  const claimEntries = claims as ClaimEntry[];
103	  return claimEntries[0].damageAmount;
104	}
